-- Recipe: BỘT VIÊN
DO $$ DECLARE v_semi UUID; v_rec UUID; BEGIN
  SELECT id INTO v_semi FROM item WHERE code = 'SEMI-BOT-VIEN' LIMIT 1;
  IF v_semi IS NULL THEN RETURN; END IF;
  IF EXISTS (SELECT 1 FROM recipe WHERE semi_product_id = v_semi) THEN RETURN; END IF;
    VALUES (v_semi, 1, TRUE, 'ACTIVE', 'APPROVED') RETURNING id INTO v_rec;
END $$;

